('A17', '魔法恢復', '靈泉湧動・魔力再生', 'support', 'heal', '被動技能。每回合自動恢復5%最大MP。等級越高恢復越多（每級+0.5%）。', '木', 0, 0, 0, 10, 0, NULL, '{"isPassive":true,"passiveType":"mpRegen","mpRestorePercent":5,"mpRestorePerLevel":0.5,"aoe":"self","aoeDescription":"被動（自身）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'self', 'none', 'rare', 1, 1, NULL, 417, 1774744854767, 1774744854767),
('A18', '聖盾', '神聖守護・聖盾之光', 'support', 'buff', '為單一隊友施加聖盾，3回合內完全免疫一次攻擊（物理或魔法皆可）。', '土', 0, 25, 5, 10, 0, NULL, '{"shield":{"type":"all","charges":1,"duration":3,"absorbPercent":100},"aoe":"single","aoeDescription":"單體（友方）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'none', 'legendary', 1, 1, NULL, 418, 1774744854767, 1774744854767),
('X01', '暗殺', '影殺無形・暗殺之道', 'special', 'attack', '從暗處發動致命一擊，50%命中率。命中時造成500%ATK傷害，且有機率即死（BOSS無效）。', '金', 500, 25, 8, 10, 0, NULL, '{"accuracyMod":-50,"instantKill":true,"instantKillChance":50,"bossImmune":true,"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'legendary', 1, 1, NULL, 501, 1774744854767, 1774744854767),
('X02', '偷竊', '妙手空空・偷竊之技', 'special', 'utility', '嘗試偷取敵方道具，30%機率成功。等級越高成功率越高（每級+3%）。', '木', 0, 15, 3, 10, 0, NULL, '{"steal":true,"stealChance":30,"stealChancePerLevel":3,"aoe":"single","aoeDescription":"單體（敵方）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'none', 'rare', 1, 1, NULL, 502, 1774744854767, 1774744854767),
('X03', '挑釁', '怒火引燃・挑釁之術', 'special', 'utility', '挑釁單一敵人，強制其在接下來3回合內只能攻擊自己。坦克型角色的核心技能。', '火', 0, 10, 4, 10, 0, NULL, '{"taunt":{"duration":3},"tauntDurationPerLevel":0.2,"aoe":"single","aoeDescription":"單體（敵方）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'none', 'common', 1, 1, NULL, 503, 1774744854767, 1774744854767),
('X04', '捨身', '捨身取義・自爆之術', 'special', 'attack', '消耗自身50%當前HP，對敵人造成400%ATK傷害。高風險高回報的自傷技能。', '火', 400, 0, 8, 10, 20, NULL, '{"selfDamagePercent":50,"aoe":"single","aoeDescription":"單體"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'atk', 'legendary', 1, 1, NULL, 504, 1774744854767, 1774744854767),
('X05', '五行封印', '封印禁術・五行封鎖', 'special', 'debuff', '封印目標的五行屬性3回合，使其五行攻擊和五行抗性全部歸零。', '無', 0, 35, 6, 10, 0, NULL, '{"sealWuxing":true,"sealDuration":3,"sealDurationPerLevel":0.2,"aoe":"single","aoeDescription":"單體（敵方）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'single', 'mtk', 'legendary', 1, 1, NULL, 505, 1774744854767, 1774744854767),
('X06', '天命共振', '天命共振・終極奧義', 'special', 'buff', '發動天命共振的終極奧義，全體隊友HP/MP各回復20%，並提升ATK/DEF/MTK 15%持續5回合。', '無', 20, 50, 10, 10, 2, NULL, '{"healType":"instant","healHpPercent":20,"healMpPercent":20,"buff":{"stat":"all","percent":15,"duration":5,"isDebuff":false},"aoe":"party","aoeDescription":"全體（己方含自身）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'party', 'mtk', 'legendary', 1, 1, NULL, 506, 1774744854767, 1774744854767),
('R01', '石化抵抗', '堅石之心・石化免疫', 'resistance', 'passive', '被動技能。有機率抵抗石化狀態。每級增加10%抵抗機率（Lv10=100%免疫）。', '土', 0, 0, 0, 10, 0, NULL, '{"isPassive":true,"passiveType":"statusResist","resistType":"petrify","resistChancePerLevel":10,"aoe":"self","aoeDescription":"被動（自身）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'self', 'none', 'common', 1, 1, NULL, 601, 1774744854767, 1774744854767),
('R02', '昏睡抵抗', '清醒之志・昏睡免疫', 'resistance', 'passive', '被動技能。有機率抵抗昏睡狀態。每級增加10%抵抗機率。', '水', 0, 0, 0, 10, 0, NULL, '{"isPassive":true,"passiveType":"statusResist","resistType":"sleep","resistChancePerLevel":10,"aoe":"self","aoeDescription":"被動（自身）"}', '{"gold":500,"soulCrystal":10}', NULL, NULL, 'self', 'none', 'common', 1, 1, NULL, 602, 1774744854767, 1774744854767);
